def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[0]
    title_shape = None
    subtitle_shape = None
    target = 'A Comprehensive Study'.lower().strip()
    # Find title and subtitle shapes
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        text = shape.text_frame.text.lower().strip()
        if shape == slide.shapes.title and text:
            title_shape = shape
        if target in text:
            subtitle_shape = shape
    if not title_shape or not subtitle_shape:
        return "Couldn't locate both title and subtitle shapes.", 0.0
    # Check that subtitle is visually below main title. Allow up to 0.25"
    # tolerance because title placeholders often have empty padding below text.
    tolerance_emu = 228600  # 0.25 inches
    title_bottom = title_shape.top + title_shape.height
    if subtitle_shape.top >= title_shape.top and subtitle_shape.top + tolerance_emu >= title_bottom:
        return "Subtitle is placed below the main title.", 1.0
    else:
        return "Subtitle is not placed below the main title.", 0.0

