def compute_score() -> tuple[str, float]:
    # We'll check that on the title slide, the only added text is the subtitle itself
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    orig_slide = orig.slides[0]
    mod_slide = mod.slides[0]
    # Gather all text on before and after
    def get_all_text(slide):
        texts = []
        for shape in slide.shapes:
            if shape.has_text_frame:
                texts.append(shape.text_frame.text.strip())
        return set(texts)
    orig_texts = get_all_text(orig_slide)
    mod_texts = get_all_text(mod_slide)
    added_texts = [t for t in mod_texts if t not in orig_texts]
    # Only permitted addition is the exact subtitle
    allowed = {'A Comprehensive Study'}
    extraneous = []
    repeat = False
    for t in added_texts:
        if t not in allowed or repeat:
            extraneous.append(t)
        if t in allowed:
            repeat = True
    if extraneous:
        return f"Found extraneous text additions on title slide: {extraneous}", 0.0
    return "No extraneous text additions on title slide.", 1.0

def compute_score() -> tuple[str, float]:
    # Check for added/removed/modified animations or transitions on slide 0 (title slide)
    title_slide_id = None
    if ppt_diff.added_slides:
        title_slide_id = ppt_diff.added_slides[0].slide_id
    else:
        # Try to get from original slides
        if ppt_diff.removed_slides:
            title_slide_id = ppt_diff.removed_slides[0].slide_id
        else:
            # Fallback: assume first slide in modifications is title slide
            if ppt_diff.modified_slides:
                title_slide_id = ppt_diff.modified_slides[0][1].slide_id
    # If not found, check index 0
    if not title_slide_id:
        from pptx import Presentation
        mod = Presentation(modified_ppt_path)
        title_slide_id = mod.slides[0].slide_id
    # Check for any added/removed/modified animations/transitions on that slide
    for anim in ppt_diff.added_animations + [b for a, b in ppt_diff.modified_animations]:
        if anim.slide_id == title_slide_id:
            return "Animation was added or modified on title slide.", 0.0
    for trans in ppt_diff.added_transitions + [b for a, b in ppt_diff.modified_transitions]:
        if trans.slide_id == title_slide_id:
            return "Transition was added or modified on title slide.", 0.0
    return "No animations or transitions added to title slide.", 1.0
